1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_FACTOR = 1.1;
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	const COMPONENT_BASE_PREMIUM = 25;
13	
14	const baseItemPremium = (item: Item): number =>
15	  BASE_PREMIUM[item.type] ?? COMPONENT_BASE_PREMIUM;
16	
17	const itemPremium = (item: Item): number =>
18	  baseItemPremium(item) * FIRST_INSURANCE_FACTOR;
19	
20	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
21	
22	const sumItemPremiums = (items: Item[]): number =>
23	  items.reduce((sum, item) => sum + itemPremium(item), 0);
24	
25	const priceQuote = (step: QuoteStep): { premium: number } => ({
26	  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
27	});
28	
29	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
30	  results: scenario.steps.map(priceQuote),
31	});
32

1	import { describe, it, expect } from "vitest";
