14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result.results[0]).toEqual({ premium: 115 });
24	  });
25	  it("a single amulet (plain, newcomer first contract) yields a premium of 71 G (60 base + 6 first + 5 fee)", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [
29	        {
30	          op: "quote",
31	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	        },
33	      ],
34	    });
35	    expect(result.results[0]).toEqual({ premium: 71 });
36	  });
37	
38	  // Quote: components and blocks
39	  it("2 runes (plain, newcomer first contract) yields a premium of 60 G (50 base + 5 first + 5 fee)", () => {
40	    const result = runScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [
43	        {
44	          op: "quote",
45	          items: [
46	            { type: "rune" },
47	            { type: "rune" },
48	          ],
49	        },
50	      ],
51	    });
52	    expect(result.results[0]).toEqual({ premium: 60 });
53	  });
54	  it.todo("3 runes form a block: base premium 60 G total");
55	  it.todo("3 runes + 3 moonstones form two blocks: base premium 120 G total");
56	
57	  // Quote: modifiers
58	  it.todo("a cursed sword applies +50% surcharge on the cursed item only");
59	  it.todo("high enchantment (level >= 5) sword applies +30% surcharge");
60	  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy total");
61	  it.todo("follow-up contract receives 15% discount on policy total");
62	  it.todo("policy with cursed sword and plain amulet: cursed surcharge applies only to cursed item");
63	
64	  // Quote: rounding and integration
65	  it.todo("premium is rounded up in MHPCO's favor");
66	  it.todo("newcomer with a cursed sword (steel, enchantment 3) yields premium of 165 G");
67	  it.todo("long-standing customer's second contract with cursed sword enchantment 7 yields 160 G");
68	
