71	  it.todo("rune damage 200 G yields payout 100 G");
72	  it.todo("enchantment >= 8 reimburses at 50% then deductible");
73	  it.todo("dragon-material item is fully reimbursed before deductible");
74	  it.todo("dragon-material + enchantment >= 8: 50% rule wins, then deductible");
75	  it.todo("dragon attack damaging sword and amulet: deductible applies per damage entry");
76	
